func TestReadySetReturnsBeadsWithSatisfiedDeps(t *testing.T) {
	d, err := NewDAG([]Node{
		{ID: "a"},
		{ID: "b", DependsOn: []string{"a"}},
		{ID: "c", DependsOn: []string{"a"}},
		{ID: "d", DependsOn: []string{"b", "c"}},
	})
